namespace BlazorApp.Services;

public class NotificationItem
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly List<NotificationItem> _notifications = new();
    private readonly Lock _lock = new();

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.AddRange(new[]
        {
            new NotificationItem { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-30) },
            new NotificationItem { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-15) },
            new NotificationItem { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
        });
    }

    /// <summary>Returns all notifications.</summary>
    public Task<List<NotificationItem>> GetNotificationsAsync()
    {
        lock (_lock)
        {
            return Task.FromResult(_notifications.OrderByDescending(n => n.Timestamp).ToList());
        }
    }

    /// <summary>Returns only notifications newer than the given id.</summary>
    public Task<List<NotificationItem>> GetNotificationsSinceAsync(int lastSeenId)
    {
        lock (_lock)
        {
            var newer = _notifications
                .Where(n => n.Id > lastSeenId)
                .OrderByDescending(n => n.Timestamp)
                .ToList();
            return Task.FromResult(newer);
        }
    }

    /// <summary>Simulates a new notification arriving (called by the background generator).</summary>
    public void AddRandom()
    {
        string[] templates =
        [
            "Server health check passed.",
            "Deployment completed successfully.",
            "New comment on your post.",
            "Your subscription was renewed.",
            "Security alert: new login detected.",
            "Backup completed.",
            "System update available.",
        ];

        lock (_lock)
        {
            _notifications.Add(new NotificationItem
            {
                Id = _nextId++,
                Message = templates[Random.Shared.Next(templates.Length)],
                Timestamp = DateTime.UtcNow,
            });
        }
    }
}

namespace BlazorApp.Services;

/// <summary>
/// Background service that periodically adds fake notifications
/// so the polling page has new data to discover.
/// </summary>
public class NotificationGenerator : BackgroundService
{
    private readonly NotificationService _notifications;

    public NotificationGenerator(NotificationService notifications)
        => _notifications = notifications;

    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(8), stoppingToken);
            _notifications.AddRandom();
        }
    }
}

